import React, { useEffect, useState, useMemo } from 'https://esm.sh/react@18.2.0';
import ReactDOM from 'https://esm.sh/react-dom@18.2.0/client';
import * as Recharts from 'https://esm.sh/recharts@2.12.7?deps=react@18.2.0';

// Custom Tooltip
const CustomTooltip = ({ active, payload, label, config }) => {
  if (active && payload && payload.length) {
    return React.createElement(
      'div',
      { 
        className: "bg-white p-2 border border-[#EEF2F7] rounded-lg min-w-[120px]",
        style: { fontFamily: '"Inter", sans-serif' }
      },
      React.createElement('div', { className: "mb-1" },
        React.createElement('p', { className: "text-[13px] font-semibold text-[#252726]" }, label)
      ),
      payload.map((entry, index) => (
        React.createElement(
          'div',
          { key: index, className: "flex items-center justify-between gap-4 py-1" },
          React.createElement('div', { className: "flex items-center gap-2" },
            React.createElement('span', { 
              className: "w-2.5 h-2.5 rounded-[2px]", 
              style: { backgroundColor: entry.fill } 
            }),
            React.createElement('span', { className: "text-[13px] text-[#737373]" }, config[entry.dataKey]?.label || entry.name)
          ),
          React.createElement('span', { className: "text-[13px] font-bold text-[#252726] tabular-nums" }, 
            new Intl.NumberFormat().format(entry.value)
          )
        )
      ))
    );
  }
  return null;
};

function IZOVerticalBarChart(props) {
  const [isLoaded, setIsLoaded] = useState(false);

  useEffect(() => {
    if (!document.getElementById('izo-font-inter')) {
      const link = document.createElement('link');
      link.id = 'izo-font-inter';
      link.rel = 'stylesheet';
      link.href = 'https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap';
      document.head.appendChild(link);
    }
    if (!document.getElementById('izo-tw-v4')) {
      const tw = document.createElement('script');
      tw.id = 'izo-tw-v4';
      tw.src = 'https://cdn.jsdelivr.net/npm/@tailwindcss/browser@4';
      tw.onload = () => setIsLoaded(true);
      document.head.appendChild(tw);
    } else {
      setIsLoaded(true);
    }
  }, []);

  const resolved = useMemo(() => {
    const raw = props.data || {};
    const series = raw.series || [];
    const rawData = raw.data || [];

    // SUPPORTED PROPS FROM DATA OBJECT
    const barSize = raw.barSize !== undefined ? raw.barSize : 36;
    const barCategoryGap = raw.barCategoryGap !== undefined ? raw.barCategoryGap : "-10%";
    const barGap = raw.barGap !== undefined ? raw.barGap : 8;
    const tickCount = raw.tickCount !== undefined ? raw.tickCount : 5;
    const chartHeight = raw.chartHeight !== undefined ? raw.chartHeight : 260; // Added chartHeight prop

    const processedData = rawData.map(item => {
      const cleanItem = { ...item };
      series.forEach(s => { cleanItem[s.key] = Number(item[s.key]) || 0; });
      return cleanItem;
    });

    const totals = {};
    series.forEach((s) => { 
      totals[s.key] = processedData.reduce((sum, d) => sum + d[s.key], 0); 
    });

    return {
      data: processedData,
      categoryKey: raw.categoryKey || "week",
      series,
      config: raw.config || {},
      totals,
      title: raw.title || "",
      subtitle: raw.subtitle || "",
      barSize,
      barCategoryGap,
      barGap,
      tickCount,
      chartHeight
    };
  }, [props.data]);

  const { data, categoryKey, series, config, totals, title, subtitle, barSize, barCategoryGap, barGap, tickCount, chartHeight } = resolved;

  if (!isLoaded) return null;

  const { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } = Recharts;

  return React.createElement(
    'div',
    { 
      style: { fontFamily: '"Inter", sans-serif' },
      className: "flex flex-col gap-6 p-6 bg-white w-full h-full overflow-hidden" 
    },

    (title || subtitle) && React.createElement(
      'div',
      { className: "flex flex-col gap-2.5" },
      title && React.createElement('h3', { className: "text-base font-semibold text-[#252726]" }, title),
      subtitle && React.createElement('p', { className: "text-xs text-[#252726]" }, subtitle)
    ),

    React.createElement(
      'div',
      { className: "flex flex-1 items-center gap-10 min-h-0 w-full" },

      React.createElement(
        'div',
        { 
          className: "flex-1 relative min-w-0", 
          style: { height: `${chartHeight}px` } // Dynamically apply height
        }, 
        React.createElement(
          ResponsiveContainer,
          { width: "100%", height: "100%" },
          React.createElement(
            BarChart,
            { 
              data: data, 
              barGap: barGap, 
              barCategoryGap: barCategoryGap, 
              margin: { top: 10, right: 0, left:-15, bottom: 0 } 
            },
            React.createElement(CartesianGrid, { vertical: false, stroke: "#EEF2F7", strokeDasharray: "0" }),
            React.createElement(XAxis, { 
              dataKey: categoryKey, 
              tickLine: false, 
              axisLine: false, 
              tick: { fontSize: 13, fill: "#737373" },
              tickMargin: 12
            }),
            React.createElement(YAxis, { 
              width: 60, 
              tickLine: false, 
              axisLine: false, 
              tick: { fontSize: 13, fill: "#737373" },
              tickCount: tickCount 
            }),
            React.createElement(Tooltip, {
              content: (tProps) => React.createElement(CustomTooltip, { ...tProps, config }),
              cursor: { fill: "#EEF2F7", opacity: 0.4 }
            }),
            series.map((s) => React.createElement(Bar, {
              key: s.key,
              dataKey: s.key,
              fill: config[s.key]?.color || "#2e8b57",
              radius: [4, 4, 4, 4],
              barSize: barSize
            }))
          )
        )
      ),

      React.createElement(
        'div',
        { className: "flex flex-col gap-3 min-w-[120px]" },
        series.map((s) => React.createElement(
          'div',
          { key: s.key, className: "flex items-center justify-between gap-3" },
          React.createElement('div', { className: "flex items-center gap-2" },
            React.createElement('span', { 
              className: "w-2.5 h-2.5 rounded-full", 
              style: { backgroundColor: config[s.key]?.color } 
            }),
            React.createElement('span', { className: "text-sm font-medium text-[#737373]" }, config[s.key]?.label || s.key)
          ),
          React.createElement('span', { className: "text-sm font-bold text-[#737373]" }, 
            totals[s.key]
          )
        ))
      )
    )
  );
}

const ConnectedComponent = Tooljet.connectComponent(IZOVerticalBarChart);
if (!window.tooljetRoot) {
  window.tooljetRoot = ReactDOM.createRoot(document.body);
}
window.tooljetRoot.render(React.createElement(ConnectedComponent));
